# 共享quiz数据存储 (文件系统作为Redis的备用)
import os
SHARED_QUIZZES_DIR = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'shared_quizzes')

# 确保目录存在
os.makedirs(SHARED_QUIZZES_DIR, exist_ok=True)

# 获取quiz文件路径
def get_quiz_file_path(quiz_id):
    return os.path.join(SHARED_QUIZZES_DIR, f'{quiz_id}.json')

# 存储共享quiz
def save_shared_quiz(quiz_id, quiz_data):
    # 添加过期时间（7天）
    quiz_data_with_expiry = quiz_data.copy()
    quiz_data_with_expiry['_expires_at'] = time.time() + 86400 * 7
    
    quiz_data_json = json.dumps(quiz_data_with_expiry)
    
    # 优先使用Redis
    if redis_client:
        try:
            redis_client.setex(f'quiz:{quiz_id}', 86400 * 7, quiz_data_json)
            return True
        except Exception as e:
            print(f'Failed to save to Redis: {e}')
    
    # 备用：保存到文件
    try:
        file_path = get_quiz_file_path(quiz_id)
        with open(file_path, 'w', encoding='utf-8') as f:
            f.write(quiz_data_json)
        return True
    except Exception as e:
        print(f'Failed to save to file: {e}')
        return False

# 获取共享quiz
def get_shared_quiz(quiz_id):
    # 优先从Redis获取
    if redis_client:
        try:
            quiz_data_json = redis_client.get(f'quiz:{quiz_id}')
            if quiz_data_json:
                quiz_data = json.loads(quiz_data_json)
                # 检查是否过期（Redis自带过期，但以防万一）
                if '_expires_at' not in quiz_data or quiz_data['_expires_at'] > time.time():
                    return quiz_data
        except Exception as e:
            print(f'Failed to get from Redis: {e}')
    
    # 备用：从文件获取
    try:
        file_path = get_quiz_file_path(quiz_id)
        if os.path.exists(file_path):
            with open(file_path, 'r', encoding='utf-8') as f:
                quiz_data = json.loads(f.read())
            # 检查是否过期
            if '_expires_at' in quiz_data and quiz_data['_expires_at'] <= time.time():
                # 删除过期文件
                try:
                    os.remove(file_path)
                except:
                    pass
                return None
            return quiz_data
    except Exception as e:
        print(f'Failed to get from file: {e}')
    
    return None

# 清理过期的quiz文件
def cleanup_expired_quizzes():
    try:
        if not os.path.exists(SHARED_QUIZZES_DIR):
            return
        now = time.time()
        for filename in os.listdir(SHARED_QUIZZES_DIR):
            if filename.endswith('.json'):
                file_path = os.path.join(SHARED_QUIZZES_DIR, filename)
                try:
                    with open(file_path, 'r', encoding='utf-8') as f:
                        quiz_data = json.loads(f.read())
                    if '_expires_at' in quiz_data and quiz_data['_expires_at'] <= now:
                        os.remove(file_path)
                        print(f'Cleaned up expired quiz: {filename}')
                except Exception as e:
                    # 如果文件损坏，直接删除
                    try:
                        os.remove(file_path)
                    except:
                        pass
                    print(f'Cleaned up corrupted quiz file: {filename}')
    except Exception as e:
        print(f'Error during cleanup: {e}')

# 辅助函数：获取用户统计
def get_user_stats():
    total_completed = 0
    total_correct = 0
    
    stats = {}
    
    for exam_type, data in USER_PROGRESS.items():
        completed_count = len(data['completed'])
        correct_count = len(data['correct'])
        accuracy = int((correct_count / completed_count * 100)) if completed_count > 0 else 0
        questions = QUESTION_BANK.get(exam_type, [])
        total_questions = len(questions)

        difficulty_counts = {'easy': 0, 'medium': 0, 'hard': 0}
        section_counts = {}
        for q in questions:
            diff = (q.get('difficulty') or 'Medium').strip().lower()
            if diff not in difficulty_counts:
                diff = 'medium'
            difficulty_counts[diff] += 1
            
            section = q.get('section')
            if section:
                if section not in section_counts:
                    section_counts[section] = 0
                section_counts[section] += 1

        if total_questions > 0:
            difficulty_percent = {
                k: int(round(v / total_questions * 100))
                for k, v in difficulty_counts.items()
            }
        else:
            difficulty_percent = {'easy': 0, 'medium': 0, 'hard': 0}
        
        stats[exam_type] = {
            'completed': completed_count,
            'accuracy': accuracy,
            'total_questions': total_questions,
            'difficulty_counts': difficulty_counts,
            'difficulty_percent': difficulty_percent,
            'section_counts': section_counts
        }
        
        total_completed += completed_count
        total_correct += correct_count
        
    total_accuracy = int((total_correct / total_completed * 100)) if total_completed > 0 else 0
    
    return {
        'total_practiced': total_completed,
        'today_completed': total_completed, # 暂用总数代替
        'today_accuracy': total_accuracy,
        'exam_stats': stats
    }


def infer_exam_type_for_question(question):
    question_id = question.get('id')
    question_text = question.get('question')
    question_topic = question.get('topic')

    for exam_type, questions in QUESTION_BANK.items():
        for q in questions:
            if q.get('id') == question_id and q.get('question') == question_text and q.get('topic') == question_topic:
                return exam_type
    return None


