# quiz结果页面
@app.route('/quiz-result')
def quiz_result():
    custom_quiz_ids = session.get('custom_quiz_questions', [])
    exam_type = session.get('custom_quiz_exam_type')
    quiz_answers = session.get('quiz_answers', {})
    quiz_start_time = session.get('quiz_start_time')
    section = session.get('custom_quiz_section')
    
    if not custom_quiz_ids or not exam_type or exam_type not in QUESTION_BANK:
        return redirect(url_for('select_exam'))
    
    # 根据id获取题目
    questions_all = QUESTION_BANK[exam_type]
    questions = []
    for q_id in custom_quiz_ids:
        q = next((qq for qq in questions_all if qq['id'] == q_id), None)
        if q:
            questions.append(q)
    
    # 计算分数并收集所有题目数据
    correct_count = 0
    all_questions = []
    
    # 确保session中有wrong_questions
    if 'wrong_questions' not in session:
        session['wrong_questions'] = []
    
    for q in questions:
        q_id_str = str(q['id'])
        user_answer = quiz_answers.get(q_id_str)
        is_correct = (user_answer == q['answer'])
        
        if is_correct:
            correct_count += 1
        else:
            # 添加错题到错题本
            wrong_item = dict(q)
            wrong_item['exam_type'] = exam_type
            # 避免重复添加
            if not any(w.get('id') == q['id'] and w.get('exam_type') == exam_type for w in session['wrong_questions']):
                session['wrong_questions'].append(wrong_item)
                session.modified = True
        
        all_questions.append({
            'question': q,
            'user_answer': user_answer,
            'is_correct': is_correct
        })
    
    total_questions = len(questions)
    incorrect_count = total_questions - correct_count
    score = int((correct_count / total_questions * 100)) if total_questions > 0 else 0
    
    # 计算耗时
    time_display = ''
    if quiz_start_time:
        total_seconds = int(time.time() - quiz_start_time)
        minutes = total_seconds // 60
        seconds = total_seconds % 60
        if minutes > 0:
            time_display = f'{minutes}:{seconds:02d}'
        else:
            time_display = f'0:{seconds:02d}'
    
    # 确定返回页面
    back_url = url_for('select_exam')
    if exam_type == 'ap_micro':
        back_url = url_for('select_section_ap_micro')
    elif exam_type == 'ap_macro':
        back_url = url_for('select_section_ap_macro')
    
    # 将本次完成的题目加入已考察记录
    seen_questions_key = f'seen_questions_{exam_type}'
    seen_question_ids = set(session.get(seen_questions_key, []))
    for q in questions:
        seen_question_ids.add(q['id'])
    session[seen_questions_key] = list(seen_question_ids)
    session.modified = True
    
    # 保存完整结果数据并生成持久化链接
    result_id = str(uuid.uuid4())
    result_data = {
        'exam_type': exam_type,
        'question_ids': [q['id'] for q in questions],
        'quiz_answers': quiz_answers,
        'quiz_start_time': quiz_start_time,
        'section': section,
        'is_result': True
    }
    save_shared_quiz(result_id, result_data)
    
    # 清理session
    session.pop('custom_quiz_questions', None)
    session.pop('custom_quiz_exam_type', None)
    session.pop('custom_quiz_section', None)
    session.pop('quiz_answers', None)
    session.pop('quiz_start_time', None)
    
    # 重定向到持久化结果页面，确保可以在任何浏览器中访问
    return redirect(url_for('shared_quiz_result', result_id=result_id))

