@app.route('/shared-quiz-result')
def shared_quiz_result():
    # 偶尔清理过期数据（10%概率）
    import random
    if random.random() < 0.1:
        cleanup_expired_quizzes()
    
    result_id = request.args.get('result_id')
    
    if result_id:
        # 通过result_id加载持久化的结果数据
        result_data = get_shared_quiz(result_id)
        if result_data and result_data.get('is_result'):
            custom_quiz_ids = result_data['question_ids']
            exam_type = result_data['exam_type']
            quiz_answers = result_data['quiz_answers']
            quiz_start_time = result_data['quiz_start_time']
            section = result_data['section']
            is_shared = True
        else:
            return 'Result not found', 404
    else:
        # 从session加载（原有逻辑）
        custom_quiz_ids = session.get('custom_quiz_questions', [])
        exam_type = session.get('custom_quiz_exam_type')
        quiz_answers = session.get('quiz_answers', {})
        quiz_start_time = session.get('quiz_start_time')
        section = session.get('custom_quiz_section')
        is_shared = session.get('is_shared_quiz', False)
    
    if not custom_quiz_ids or not exam_type or exam_type not in QUESTION_BANK:
        return 'Quiz not found', 404
    
    # 根据id获取题目
    questions_all = QUESTION_BANK[exam_type]
    questions = []
    for q_id in custom_quiz_ids:
        q = next((qq for qq in questions_all if qq['id'] == q_id), None)
        if q:
            questions.append(q)
    
    # 计算分数并收集所有题目数据
    correct_count = 0
    all_questions = []
    
    # 只有不是从result_id加载时才修改用户的错题本和进度
    from_result_id = request.args.get('result_id') is not None
    
    if not from_result_id:
        # 确保session中有wrong_questions
        if 'wrong_questions' not in session:
            session['wrong_questions'] = []
    
    for q in questions:
        q_id_str = str(q['id'])
        user_answer = quiz_answers.get(q_id_str)
        is_correct = (user_answer == q['answer'])
        
        if is_correct:
            correct_count += 1
        else:
            # 只有不是从result_id加载时才添加错题到错题本
            if not from_result_id:
                wrong_item = dict(q)
                wrong_item['exam_type'] = exam_type
                # 避免重复添加
                if not any(w.get('id') == q['id'] and w.get('exam_type') == exam_type for w in session['wrong_questions']):
                    session['wrong_questions'].append(wrong_item)
                    session.modified = True
        
        all_questions.append({
            'question': q,
            'user_answer': user_answer,
            'is_correct': is_correct
        })
    
    total_questions = len(questions)
    incorrect_count = total_questions - correct_count
    score = int((correct_count / total_questions * 100)) if total_questions > 0 else 0
    
    # 计算耗时
    time_display = ''
    if quiz_start_time and not from_result_id:
        total_seconds = int(time.time() - quiz_start_time)
        minutes = total_seconds // 60
        seconds = total_seconds % 60
        if minutes > 0:
            time_display = f'{minutes}:{seconds:02d}'
        else:
            time_display = f'0:{seconds:02d}'
    
    # 将本次完成的题目加入已考察记录（只有不是从result_id加载时）
    if not from_result_id:
        seen_questions_key = f'seen_questions_{exam_type}'
        seen_question_ids = set(session.get(seen_questions_key, []))
        for q in questions:
            seen_question_ids.add(q['id'])
        session[seen_questions_key] = list(seen_question_ids)
        session.modified = True
    
    return render_template('quiz_result_shared.html',
                           score=score,
                           correct_count=correct_count,
                           incorrect_count=incorrect_count,
                           all_questions=all_questions,
                           time_display=time_display,
                           section=section,
                           is_shared=is_shared,
                           exam_type=exam_type,
                           languages=LANGUAGES,
                           current_language=get_locale())

@app.route('/practice/<exam_type>')
@app.route('/practice/<exam_type>/<int:question_index>')
def practice(exam_type, question_index=0):
    if exam_type not in QUESTION_BANK:
        return redirect(url_for('select_exam'))
    
    difficulty = request.args.get('difficulty')
    difficulty = difficulty.strip().lower() if isinstance(difficulty, str) else None
    difficulty_map = {'easy': 'Easy', 'medium': 'Medium', 'hard': 'Hard'}
    difficulty_label = difficulty_map.get(difficulty)
    
    section = request.args.get('section')

    questions_all = QUESTION_BANK[exam_type]
    questions = questions_all
    
    if difficulty_label:
        questions = [q for q in questions if (q.get('difficulty') or 'Medium') == difficulty_label]
    
    if section:
        questions = [q for q in questions if q.get('section') == section]

    if not questions:
        return redirect(url_for('practice', exam_type=exam_type))

    total_questions = len(questions)
    
    # 确保索引有效
    if question_index >= total_questions:
        return redirect(url_for('select_exam'))
        
    current_question = questions[question_index]
    
    # 获取当前进度
    progress = USER_PROGRESS.get(exam_type, {'completed': set(), 'correct': set()})
    completed_count = len(progress['completed'])
    accuracy = 0
    if completed_count > 0:
        accuracy = int(len(progress['correct']) / completed_count * 100)
        
    next_url = None
    if exam_type == 'ap_micro':
        back_url = url_for('select_section_ap_micro')
        finish_url = url_for('select_section_ap_micro')
    elif exam_type == 'ap_macro':
        back_url = url_for('select_section_ap_macro')
        finish_url = url_for('select_section_ap_macro')
    else:
        back_url = url_for('select_exam')
        finish_url = url_for('select_exam')
    
    if question_index + 1 < total_questions:
        url_params = {'exam_type': exam_type, 'question_index': question_index + 1}
        if difficulty_label:
            url_params['difficulty'] = difficulty_label
        if section:
            url_params['section'] = section
        next_url = url_for('practice', **url_params)

    return render_template('practice.html', 
                           exam_type=exam_type,
                           question=current_question,
                           question_index=question_index,
                           total_questions=total_questions,
                           completed_count=completed_count,
                           accuracy=accuracy,
                           back_url=back_url,
                           next_url=next_url,
                           finish_url=finish_url,
                           difficulty_filter=difficulty_label,
                           section_filter=section,
                           languages=LANGUAGES, 
                           current_language=get_locale())


